"""Встроенные изображения интерфейса (логотип, кнопка обновления баз). Перегенерация: py -3 tools/_gen_embedded_png.py"""

from __future__ import annotations

import base64

import tkinter as tk

_EMBEDDED_LOGO_PNG_B64 = ""

_EMBEDDED_REFRESH_BTN_PNG_B64 = "iVBORw0KGgoAAAANSUhEUgAAABYAAAAWCAYAAADEtGw7AAAAd0lEQVR42mNgGCjw4cuP/9gw1Q0k2wJiDSTJAmwalEI74BifwSB5og1GNhSf4TBxmhiK03B8hhIKX2Q1VDMUb0SSE1k0NxibOooNxqV24AzGZzg+dWSnDKINJTaDEJNpyM59JBtKTCFEKOzpX2zStKCnedVEKQAAcUEkMGWkHFsAAAAASUVORK5CYII="


def embedded_logo_png_bytes() -> bytes:
    return base64.b64decode(_EMBEDDED_LOGO_PNG_B64)


def embedded_refresh_button_png_bytes() -> bytes:
    return base64.b64decode(_EMBEDDED_REFRESH_BTN_PNG_B64)


def apply_embedded_window_icon_from_parent(win: tk.Misc, parent: tk.Misc) -> None:
    """Тот же значок, что у главного окна (bundle/icon.ico — атрибут _window_icon_ico_path на корне tk)."""
    top = parent.winfo_toplevel()
    path = getattr(top, "_window_icon_ico_path", None)
    if path is None:
        return
    try:
        win.iconbitmap(str(path))
    except (tk.TclError, OSError):
        pass
